1	/**
2	 * Session Log Writer — append-only per-session JSONL file.
3	 *
4	 * Log files live under ~/.yoke/<fingerprint>/logs/<workflowId>/<sessionId>.jsonl.
5	 * The fingerprint is derived from the configDir so that parallel yoke projects
6	 * on the same machine never collide (RC-4).
7	 *
8	 * The writer holds an open FileHandle opened with O_APPEND | O_CREAT (flag 'a').
9	 * All writes go through fs.FileHandle.appendFile — no seek, no random access (RC-1).
10	 *
11	 * Lifetime: open() on session spawn → writeLine() × N → close() on session end.
12	 * The file lives in ~/.yoke/, not in the worktree, so it survives worktree
13	 * teardown and cleanup (AC-3).
14	 */
15	
16	import * as crypto from 'crypto';
17	import * as fs from 'fs';
18	import * as os from 'os';
19	import * as path from 'path';
20	import type { DbPool } from '../storage/db.js';
21	
22	// ---------------------------------------------------------------------------
23	// Path utilities
24	// ---------------------------------------------------------------------------
25	
26	/**
27	 * Log retention is governed by config.retention.stream_json_logs (max_age_days,
28	 * max_total_bytes). No automatic cleanup runs in the writer — a separate
29	 * background maintenance task scans ~/.yoke/<fingerprint>/logs/ and prunes
30	 * files that exceed the retention policy (RC-2). The writer itself is append-only
31	 * and never deletes or truncates files.
32	 */
33	
34	/**
35	 * Derives a 16-hex-char fingerprint from the config directory absolute path.
36	 * SHA-256 of the path string, first 16 hex chars.
37	 * Different configDirs → different fingerprints → no log path collisions (RC-4).
38	 */
39	export function makeFingerprint(configDir: string): string {
40	  return crypto.createHash('sha256').update(configDir).digest('hex').slice(0, 16);
41	}
42	
43	/**
44	 * Constructs the absolute path for a session's JSONL log file.
45	 *
46	 * Format: <homeDir>/.yoke/<fingerprint>/logs/<workflowId>/<sessionId>.jsonl
47	 *
48	 * @param configDir  Absolute path to the directory containing .yoke.yml.
49	 * @param workflowId Workflow row ID.
50	 * @param sessionId  Session row ID.
51	 * @param homeDir    Override for os.homedir() (tests only).
52	 */
53	export function makeSessionLogPath(opts: {
54	  configDir: string;
55	  workflowId: string;
56	  sessionId: string;
57	  homeDir?: string;
58	}): string {
59	  const { configDir, workflowId, sessionId, homeDir = os.homedir() } = opts;
60	  const fingerprint = makeFingerprint(configDir);
61	  return path.join(homeDir, '.yoke', fingerprint, 'logs', workflowId, `${sessionId}.jsonl`);
62	}
63	
64	// ---------------------------------------------------------------------------
65	// SessionLogWriter
66	// ---------------------------------------------------------------------------
67	
68	/**
69	 * Append-only JSONL writer for a single session.
70	 *
71	 * Usage:
72	 *   const writer = new SessionLogWriter(logPath);
73	 *   await writer.open();          // creates dirs + opens file handle
74	 *   await writer.writeLine(line); // append one JSONL line
75	 *   await writer.close();         // flush + close
76	 */
77	export class SessionLogWriter {
78	  private fileHandle: fs.promises.FileHandle | null = null;
79	
80	  constructor(readonly logPath: string) {}
81	
82	  /**
83	   * Creates parent directories (recursive, idempotent) and opens the file
84	   * for appending (O_APPEND | O_CREAT). Must be called before writeLine().
85	   *
86	   * Throws on any I/O error (EACCES, EROFS, etc.).
87	   */
88	  async open(): Promise<void> {
89	    await fs.promises.mkdir(path.dirname(this.logPath), { recursive: true });
90	    this.fileHandle = await fs.promises.open(this.logPath, 'a');
91	  }
92	
93	  /**
94	   * Appends one JSONL line followed by a \n newline.
95	   * No seek is performed; the 'a' flag guarantees atomic append on POSIX.
96	   *
97	   * Throws if open() was not called first.
98	   * Throws on any I/O write error.
99	   */
100	  async writeLine(line: string): Promise<void> {
101	    if (!this.fileHandle) {
102	      throw new Error('SessionLogWriter: open() must be called before writeLine()');
103	    }
104	    await this.fileHandle.appendFile(line + '\n', { encoding: 'utf8' });
105	  }
106	
107	  /**
108	   * Closes the file handle. Safe to call multiple times; subsequent calls
109	   * are no-ops (fileHandle is nulled before awaiting close()).
110	   */
111	  async close(): Promise<void> {
112	    const fh = this.fileHandle;
113	    this.fileHandle = null;
114	    if (fh) await fh.close();
115	  }
116	
117	  /** True after open() and before close(). */
118	  get isOpen(): boolean {
119	    return this.fileHandle !== null;
120	  }
121	}
122	
123	// ---------------------------------------------------------------------------
124	// Session spawn helper — AC-4
125	// ---------------------------------------------------------------------------
126	
127	/**
128	 * Computes the log path, writes sessions.session_log_path in SQLite, creates
129	 * parent directories, opens the log file for appending, and returns the writer.
130	 *
131	 * Call this at session spawn time (before ProcessManager.spawn()):
132	 *   const { writer, logPath } = await openSessionLog(db, { configDir, workflowId, sessionId });
133	 *   const handle = await processManager.spawn({ ..., logWriter: writer });
134	 *
135	 * Writing sessions.session_log_path BEFORE the writer is opened ensures the
136	 * HTTP endpoint can serve the path even if the process crashes before the
137	 * first line is written (AC-4).
138	 *
139	 * @param db         DbPool for the SQLite write. The writer updates
140	 *                   sessions.session_log_path via db.writer directly (not via
141	 *                   a transaction wrapper — callers that need atomicity with
142	 *                   other writes should call this inside their own transaction).
143	 * @param opts.configDir  Absolute path to the directory containing .yoke.yml.
144	 * @param opts.workflowId Workflow row ID.
145	 * @param opts.sessionId  Session row ID.
146	 * @param opts.homeDir    Override for os.homedir() (tests only).
147	 */
148	export async function openSessionLog(
149	  db: DbPool,
150	  opts: {
151	    configDir: string;
152	    workflowId: string;
153	    sessionId: string;
154	    homeDir?: string;
155	  },
156	): Promise<{ writer: SessionLogWriter; logPath: string }> {
157	  const logPath = makeSessionLogPath(opts);
158	
159	  // AC-4: set sessions.session_log_path before opening the file so the HTTP
160	  // endpoint can serve the path immediately — even if the process hasn't
161	  // written any lines yet.
162	  db.writer
163	    .prepare('UPDATE sessions SET session_log_path = ? WHERE id = ?')
164	    .run(logPath, opts.sessionId);
165	
166	  const writer = new SessionLogWriter(logPath);
167	  await writer.open();
168	  return { writer, logPath };
169	}
