1	/**
2	 * Session Log Reader — paged JSONL file reader for the HTTP endpoint.
3	 *
4	 * Reads directly from the .jsonl file on disk (RC-3).
5	 * SQLite stores only the path pointer (sessions.session_log_path).
6	 *
7	 * Paging model:
8	 *   sinceSeq — number of lines to skip from the start of the file (0-based count).
9	 *   limit     — max lines to return per page, clamped to [1, MAX_PAGE_SIZE].
10	 *
11	 * The caller uses nextSeq from one response as sinceSeq in the next request
12	 * to page through the file in order.
13	 */
14	
15	import * as fs from 'fs';
16	import * as readline from 'readline';
17	
18	/** Hard cap on lines returned per page. */
19	export const MAX_PAGE_SIZE = 1000;
20	
21	/** Result of a single paged read. */
22	export interface LogPage {
23	  /** Raw JSONL lines in original (append) order, no trailing newline. */
24	  entries: string[];
25	  /** Pass as sinceSeq in the next request to continue from here. */
26	  nextSeq: number;
27	  /** True if the file contains more lines beyond this page. */
28	  hasMore: boolean;
29	}
30	
31	/**
32	 * Reads a page of lines from a session JSONL log file.
33	 *
34	 * Reads the file via a streaming readline interface — no full-file buffer
35	 * in memory (RC-3, file is never loaded into SQLite).
36	 *
37	 * @param logPath  Absolute path to the session .jsonl file.
38	 * @param sinceSeq Lines to skip from the beginning (0 = start at line 1).
39	 * @param limit    Max lines to return. Clamped to [1, MAX_PAGE_SIZE].
40	 *
41	 * @returns LogPage if the file is readable; null if the file does not exist
42	 *          or cannot be accessed (ENOENT, EACCES, etc.).
43	 */
44	export async function readLogPage(
45	  logPath: string,
46	  sinceSeq: number,
47	  limit: number,
48	): Promise<LogPage | null> {
49	  // Fast existence / readability check — returns null on any access error.
50	  try {
51	    await fs.promises.access(logPath, fs.constants.R_OK);
52	  } catch {
53	    return null;
54	  }
55	
56	  const clampedLimit = Math.min(Math.max(1, limit), MAX_PAGE_SIZE);
57	  // Collect one extra line to cheaply detect whether more lines follow.
58	  const toCollect = clampedLimit + 1;
59	
60	  const entries: string[] = [];
61	  let lineNum = 0;
62	
63	  await new Promise<void>((resolve, reject) => {
64	    const stream = fs.createReadStream(logPath, { encoding: 'utf8' });
65	    const rl = readline.createInterface({ input: stream, crlfDelay: Infinity });
66	
67	    rl.on('line', (line) => {
68	      lineNum++;
69	      // Skip the first sinceSeq lines.
70	      if (lineNum <= sinceSeq) return;
71	      // Collect up to toCollect lines (clampedLimit + 1 probe line).
72	      if (entries.length < toCollect) {
73	        entries.push(line);
74	      }
75	    });
76	
77	    rl.on('close', resolve);
78	
79	    // Propagate stream errors; close readline first to avoid double-resolve.
80	    stream.on('error', (err) => {
81	      rl.close();
82	      reject(err);
83	    });
84	    rl.on('error', reject);
85	  });
86	
87	  const hasMore = entries.length > clampedLimit;
88	  // Remove the extra probe line so callers receive at most clampedLimit entries.
89	  if (hasMore) entries.pop();
90	
91	  return {
92	    entries,
93	    nextSeq: sinceSeq + entries.length,
94	    hasMore,
95	  };
96	}
